INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('8204cda9-03a0-47ab-bb26-89811ab962bf', '2026-03-19', 22, 3, 1, 2, 1, '72歳おばあちゃんソフトバンク光8年目、お父さんと共にWi-Fiへの認識が薄い方で、サポートという面で選んでもらえた。営業はかなりきてるらしいたーだ料金下がる言われて今の5700円らしいので下がらんねやろうなという意識があった人、携帯は楽天で会社から来てて無料らしいそんなんあんな、吐き出し0円かなり熱い', 'アポになった形ではあるけど、速度ニーズおおあり夫婦共にゲームをする方。の奥さん方で副主権、速度速い方が良くて今実測値400-500出てるとのこと、たーだ携帯au２台たーだauはVタイプだったので勝てるわけもなくSo-netを提案なんとSo-net1G10ギガ共に対応していて、そこで旦那さんに聞いてみるわとのこと、ただ今速度問題なく10年以上きてるからなーとのこと。', '残4日', 'よきち。', 'とくにない。', 'やすみ。', '学びなし。', NULL, '0524dcfa-685f-4635-971b-39c7899da7cd') ON CONFLICT (sales_rep_id, report_date) DO UPDATE SET visits=EXCLUDED.visits, organization_id=EXCLUDED.organization_id;
