INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('12f0a0dc-10d3-4bbb-846c-facd48bd185e', '2026-03-21', 315, 9, 2, 2, 0, NULL, 'ベイコム3800円速度ニーズなし料金ニーズなし', '残8日', '今ニーズがない旦那さんに、「今はないかもしれないがこれから今いる息子さん娘さん大きくなってきた時にスマホを持ち出した場合｣などの将来の話をすることがとても刺さっていた。今の現状も大事だけど、過去、未来の話をすることで刺さる人がたくさんいるので、その人たちには積極的に未来、過去トーク使っていくべきだと思った。', 'ほぼ確アポができた時にできるだけ期待しないようにしているが、心の隅っこで期待している自分がいたこと。
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('c3b9f845-f37c-4fb5-b76c-750b9b22fc1f', '2026-03-21', 100, 10, 2, 2, 0, NULL, NULL, '残3日', '前回より同じことを復唱したりすることはなかった。
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('db4065a2-ecba-4248-8ad6-edbb9fb456cb', '2026-03-21', 40, 4, 0, 2, 0, NULL, 'J:comネッテレ5000円認識、料金説明で料金に関しては刺さってたが、怪しさ払拭、理解させるの不足で失注。娘相談と逃げられた', '残5日', NULL, 'J:comの熱い案件には出会ってたがめんどくささや、不信感を拭えず、温度感も上げられなかった。自分のテンションがそもそも低いのもある。ロープレを1人でする機会を増やす。', 'ロープレ増やす。テンションあげてお客さんの温度感をあげる。', NULL, '寺本いい現場視点ありがとう！', '0524dcfa-685f-4635-971b-39c7899da7cd') ON CONFLICT (sales_rep_id, report_date) DO UPDATE SET visits=EXCLUDED.visits, organization_id=EXCLUDED.organization_id;
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('c3b9f845-f37c-4fb5-b76c-750b9b22fc1f', '2026-03-22', 75, 3, 1, 1, 1, '20代くらいの1歳未満の娘さんがいるお母さん。ちょっと前にwifiを契約しようとしたが、取りやめたためちょうど旦那とwifiの相談をしていたらしい。前契約しようとらしてたwifiはdocomoで高かったからやめたらしい。そこで僕たちならめちゃくちゃ安い料金でご案内できますよ！っていい推したらいい反応をしてもらえた。今僕新人なんで詳しい案内はできないんですけど、すぐに上司呼びますねって言って宅内に入れさせてもらった。その間は料金の方は期待しててくださいねって言って、おかあさんの旦那の愚痴や育児のストレスなどで話しを盛り上がったり、wifi無しで今までどうしてたか聞いたりして寺本の到着を待ってた。', NULL, '残2日', '昨日フィードバックでしゃべりに抑揚をつけようと言われたので、そこを重点的に意識して話すことができた。', 'SB光でwifi+携帯+光熱費すべてをまとめてるお客さんがいて、乗り換えて安くなるかわからなかったから、自信をもって案内することができずお客さんの興味に引っ掛からなかった。細かい料金の知識をつけることでお客さんにマウントをとれると思う。', 'お客さんと対面して、ロープレの順番通りに話せないことがちょくちょくあったから、なるべくロープレの順張り通りに話す！', NULL, '初受注うれしい。でも運が良かっただけだから、自分の実力で受注できるよう頑張ります！', '0524dcfa-685f-4635-971b-39c7899da7cd') ON CONFLICT (sales_rep_id, report_date) DO UPDATE SET visits=EXCLUDED.visits, organization_id=EXCLUDED.organization_id;
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('8204cda9-03a0-47ab-bb26-89811ab962bf', '2026-03-23', 78, 8, 4, 3, 0, 'アポになった奴、ベイコムといざこざがあったしかも営業マンから、契約して、営業マン飛んで、違約金60000円払ってる方で心配と不安点が多すぎたっていうのがあったってのがある。', '第三者ぶちぎれ案件', '残7日', '田代あぽしっかり回収できた', '自分が商談入ってしまって、アポに行くのが遅れたってのがある。', '明後日今日のしっかりしばく', NULL, NULL, '0524dcfa-685f-4635-971b-39c7899da7cd') ON CONFLICT (sales_rep_id, report_date) DO UPDATE SET visits=EXCLUDED.visits, organization_id=EXCLUDED.organization_id;
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('0333fa7a-d0d5-4f27-b4c6-da21767f9a3d', '2026-03-23', 50, 3, 3, 1, 1, 'おばあちゃん
INSERT INTO daily_reports (sales_rep_id, report_date, visits, net_meetings, owner_meetings, negotiations, acquisitions, acquisition_case, lost_case, remaining_work, good_points, issues, improvements, learnings, gratitude, organization_id) VALUES ('4dcb189c-506c-4cce-adea-7be8581c4d54', '2026-03-23', 100, 3, 3, 3, 1, 'おばあちゃんがWi-Fi何の為につけてるか分からずに何年もつけててそろそろ辞めようかなとおもってるって言われたけどWi-Fiつけてる意味を教えてあげたらめちゃくちゃ喜んでくれてそっから料金のこととかを伝えてあげたら料金安い方がやっぱ嬉しいと言ってくれて速度は興味なさそうだったけどWi-Fiをそんないらない人から取れてよかった', '第三者確認で一時間半くらい話したおばあちゃんで料金ニーズがめちゃくちゃあって料金で結構フックかかってたけど娘に電話をかけた時にキレられて時間を無駄にしたので先に第三者確認をしていたら時間を無駄にしていなかった', '残2日', 'Wi-Fiいらない人から契約を取れたこと。
